import React, { useState, useEffect } from 'react';
import { adminAPI } from '../services/api';
import './Dashboard.css';

export default function AdminDashboard() {
  const [stats, setStats] = useState(null);
  const [users, setUsers] = useState([]);
  const [auctions, setAuctions] = useState([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    Promise.all([
      adminAPI.getStats(),
      adminAPI.getUsers(),
      adminAPI.getAuctions()
    ])
      .then(([s, u, a]) => {
        setStats(s.data.data);
        setUsers(u.data.data);
        setAuctions(a.data.data);
      })
      .catch(() => {})
      .finally(() => setLoading(false));
  }, []);

  const verifyArtist = async (id) => {
    try {
      await adminAPI.verifyArtist(id);
      setUsers((prev) => prev.map((u) => (u._id === id ? { ...u, verified: true } : u)));
    } catch (e) {}
  };

  const removeArtwork = async (id) => {
    if (!window.confirm('Remove this artwork?')) return;
    try {
      await adminAPI.removeArtwork(id);
      setAuctions((prev) => prev.filter((a) => a._id !== id));
    } catch (e) {}
  };

  if (loading) return <div className="loading">Loading...</div>;

  return (
    <div className="dashboard admin-dashboard">
      <h1>Admin Dashboard</h1>
      {stats && (
        <div className="stats-grid">
          <div className="stat-card card">
            <strong>{stats.totalUsers}</strong>
            <span>Total Users</span>
          </div>
          <div className="stat-card card">
            <strong>{stats.totalArtists}</strong>
            <span>Artists</span>
          </div>
          <div className="stat-card card">
            <strong>{stats.totalArtworks}</strong>
            <span>Artworks</span>
          </div>
          <div className="stat-card card">
            <strong>{stats.activeAuctions}</strong>
            <span>Active Auctions</span>
          </div>
          <div className="stat-card card">
            <strong>{stats.totalBids}</strong>
            <span>Total Bids</span>
          </div>
        </div>
      )}

      <section className="admin-section">
        <h2>Users</h2>
        <div className="table-wrap">
          <table>
            <thead>
              <tr>
                <th>Name</th>
                <th>Email</th>
                <th>Role</th>
                <th>Verified</th>
                <th>Action</th>
              </tr>
            </thead>
            <tbody>
              {users.map((u) => (
                <tr key={u._id}>
                  <td>{u.name}</td>
                  <td>{u.email}</td>
                  <td>{u.role}</td>
                  <td>{u.verified ? 'Yes' : 'No'}</td>
                  <td>
                    {u.role === 'artist' && !u.verified && (
                      <button className="btn btn-primary btn-sm" onClick={() => verifyArtist(u._id)}>
                        Verify
                      </button>
                    )}
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      </section>

      <section className="admin-section">
        <h2>Auctions</h2>
        <div className="table-wrap">
          <table>
            <thead>
              <tr>
                <th>Title</th>
                <th>Artist</th>
                <th>Status</th>
                <th>Current Bid</th>
                <th>Action</th>
              </tr>
            </thead>
            <tbody>
              {auctions.map((a) => (
                <tr key={a._id}>
                  <td>{a.title}</td>
                  <td>{a.artistId?.name}</td>
                  <td>{a.status}</td>
                  <td>${a.currentBid || a.startingPrice}</td>
                  <td>
                    <button className="btn btn-danger btn-sm" onClick={() => removeArtwork(a._id)}>
                      Remove
                    </button>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      </section>
    </div>
  );
}
